import{_ as r,o as a,c as t,a4 as o}from"./chunks/framework.E9a65_Io.js";const u=JSON.parse('{"title":"你的奖励！","description":"","frontmatter":{},"headers":[],"relativePath":"your-reward!.md","filePath":"your-reward!.md"}'),n={name:"your-reward!.md"};function s(_,e,p,d,i,c){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="你的奖励" tabindex="-1">你的奖励！ <a class="header-anchor" href="#你的奖励" aria-label="Permalink to &quot;你的奖励！&quot;">​</a></h1><p>&quot;你的奖励！&quot;是一种矿石，如果你的存档是在 2024 年 10 月 1 日之前创建的，就可以获得。</p><p>该矿石会发放给那些提前做好准备、在 10 月 1 日一到就立即获取的玩家，或者是耐心等到那一刻的玩家。</p><p>该矿石可获得变体版本——电击、辐射和爆炸三种都有可能。大多数玩家获得的是普通形态。但如果你运气够好，可以获得变体版本。变体的概率为：电击 1/3，辐射 1/15，爆炸 1/30。</p><p>目前该矿石<strong>已无法获得</strong>，除非你的存档还未领取过&quot;你的奖励！&quot;（即存档创建于 2024 年 10 月 1 日之前）。</p><hr><p><em>由 <a href="https://the-silly-caverns.fandom.com/wiki/Your_Reward!" target="_blank" rel="noreferrer">笨猫探穴 Wiki</a> 汉化</em></p>',7)])])}const m=r(n,[["render",s]]);export{u as __pageData,m as default};
